WITH ftp AS (
  SELECT COALESCE(
    (SELECT value::numeric FROM sync_state WHERE key = 'configured_ftp' AND value::numeric > 0),
    (SELECT ROUND(MAX(avg_20min) * 0.95) FROM (
      SELECT AVG(s.power) OVER (PARTITION BY s.activity_id ORDER BY s.time_offset RANGE BETWEEN 1199 PRECEDING AND CURRENT ROW) AS avg_20min
      FROM activity_streams s
      JOIN activities a ON a.id = s.activity_id
      WHERE a.date >= CURRENT_DATE - interval '90 days'
        AND s.power IS NOT NULL AND s.power > 0
    ) sub WHERE avg_20min IS NOT NULL),
    (SELECT percentile_cont(0.95) WITHIN GROUP (ORDER BY avg_power) FROM activities WHERE avg_power IS NOT NULL AND avg_power > 0)
  ) AS ftp_val
) SELECT ftp_val AS "FTP" FROM ftp;

SELECT ROUND((a.ctl - b.ctl)::numeric, 1) AS "6w CTL Δ"
FROM (SELECT ctl FROM athlete_stats ORDER BY date DESC LIMIT 1) a,
     (SELECT ctl FROM athlete_stats WHERE date <= CURRENT_DATE - 42 ORDER BY date DESC LIMIT 1) b;
